        if (v[m] < v[l]) std::swap(v[l], v[m]);
        if (v[h] < v[l]) std::swap(v[l], v[h]);
        if (v[h] < v[m]) std::swap(v[m], v[h]);
        p = v[m];
        while (k <= j) {
            if (v[k] < p) std::swap(v[i++], v[k++]);
            else if (v[k] > p) std::swap(v[j--], v[k]);
            else k++;
        }
        if (i - l < h - j) { quicksort(v, l, i - 1); l = j + 1; }
        else { quicksort(v, j + 1, h); h = i - 1; }
